#!/bin/bash
# Setup script for Azure AI Content Understanding Java SDK users
# This script sets up the environment for running samples (JDK + Maven based).

set -e

# Determine script directory and package root
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PACKAGE_ROOT="$(cd "$SCRIPT_DIR/../../../.." && pwd)"

echo "=== Azure AI Content Understanding (Java) - User Environment Setup ==="
echo "Package root: $PACKAGE_ROOT"
echo ""

cd "$PACKAGE_ROOT"

# Step 1: Verify toolchain
echo "Step 1: Verifying toolchain..."
if ! command -v java >/dev/null 2>&1; then
    echo "  ✗ 'java' not found in PATH. Install JDK 8+ (e.g., Microsoft Build of OpenJDK or Temurin)."
    exit 1
fi
if ! command -v mvn >/dev/null 2>&1; then
    echo "  ✗ 'mvn' not found in PATH. Install Apache Maven 3.6+."
    exit 1
fi
echo "  ✓ Java:  $(java -version 2>&1 | head -n 1)"
echo "  ✓ Maven: $(mvn -version 2>&1 | head -n 1)"
echo ""

# Step 2: Install SDK dependencies
echo "Step 2: Installing SDK dependencies..."
read -p "Installation mode — (A) Download deps only (recommended) | (B) Local build from source [A/b]: " install_mode
install_mode="${install_mode:-A}"
if [[ "$install_mode" =~ ^[Bb]$ ]]; then
    echo "  Running: mvn install -DskipTests -Djacoco.skip=true"
    mvn install -DskipTests -Djacoco.skip=true -q
else
    echo "  Running: mvn dependency:resolve"
    mvn dependency:resolve -q
fi
echo "  ✓ Dependencies ready"
echo ""

# Step 3: Configure .env file
echo "Step 3: Configuring .env file..."
ENV_FILE="$PACKAGE_ROOT/.env"
if [ -f "$ENV_FILE" ]; then
    echo "  ⚠ .env file already exists — NOT overwriting."
    echo "    To start fresh, delete it manually: rm \"$ENV_FILE\""
    read -p "  Continue with existing .env? (Y/n): " keep_env
    if [[ "$keep_env" =~ ^[Nn]$ ]]; then
        echo "  Aborting. Remove .env and re-run this script."
        exit 1
    fi
    CREATE_ENV=false
else
    CREATE_ENV=true
fi

if [ "$CREATE_ENV" = true ]; then
    read -p "Would you like to configure variables interactively now? (Y/n): " configure_now
    configure_now="${configure_now:-Y}"
    if [[ "$configure_now" =~ ^[Yy]$ ]]; then
        # CONTENTUNDERSTANDING_ENDPOINT
        read -p "  CONTENTUNDERSTANDING_ENDPOINT (e.g., https://<resource>.services.ai.azure.com/): " endpoint

        # Auth method
        echo "  Authentication:"
        echo "    (A) DefaultAzureCredential via 'az login' (recommended)"
        echo "    (B) API Key"
        read -p "  Choose [A/b]: " auth_mode
        auth_mode="${auth_mode:-A}"
        api_key=""
        if [[ "$auth_mode" =~ ^[Bb]$ ]]; then
            read -p "  CONTENTUNDERSTANDING_KEY: " api_key
        else
            echo "  ℹ Using DefaultAzureCredential — remember to run 'az login' before invoking samples."
        fi

        # Deployment names
        read -p "  GPT_4_1_DEPLOYMENT (default: gpt-4.1): " gpt41
        gpt41="${gpt41:-gpt-4.1}"
        read -p "  GPT_4_1_MINI_DEPLOYMENT (default: gpt-4.1-mini): " gpt41mini
        gpt41mini="${gpt41mini:-gpt-4.1-mini}"
        read -p "  TEXT_EMBEDDING_3_LARGE_DEPLOYMENT (default: text-embedding-3-large): " embedding
        embedding="${embedding:-text-embedding-3-large}"

        # Cross-resource copy
        read -p "  Configure cross-resource copy vars for Sample15? (y/N): " want_copy
        src_rid=""; src_region=""; tgt_ep=""; tgt_key=""; tgt_rid=""; tgt_region=""
        if [[ "$want_copy" =~ ^[Yy]$ ]]; then
            read -p "    Source resource ID: " src_rid
            read -p "    Source region (e.g., eastus): " src_region
            read -p "    Target endpoint: " tgt_ep
            read -p "    Target API key (blank = DefaultAzureCredential): " tgt_key
            read -p "    Target resource ID: " tgt_rid
            read -p "    Target region (e.g., swedencentral): " tgt_region
        fi

        cat > "$ENV_FILE" <<EOF
# Azure AI Content Understanding - Environment Variables
# Generated by cu-sdk-setup/scripts/setup_user_env.sh

# Required: Your Microsoft Foundry resource endpoint
CONTENTUNDERSTANDING_ENDPOINT=$endpoint

# Optional: API key (leave empty to use DefaultAzureCredential via az login)
CONTENTUNDERSTANDING_KEY=$api_key

# Model deployment names (used by Sample00_UpdateDefaults)
GPT_4_1_DEPLOYMENT=$gpt41
GPT_4_1_MINI_DEPLOYMENT=$gpt41mini
TEXT_EMBEDDING_3_LARGE_DEPLOYMENT=$embedding
EOF

        if [[ "$want_copy" =~ ^[Yy]$ ]]; then
            cat >> "$ENV_FILE" <<EOF

# Cross-resource copy settings (only for Sample15_GrantCopyAuth)
CONTENTUNDERSTANDING_SOURCE_RESOURCE_ID=$src_rid
CONTENTUNDERSTANDING_SOURCE_REGION=$src_region
CONTENTUNDERSTANDING_TARGET_ENDPOINT=$tgt_ep
CONTENTUNDERSTANDING_TARGET_KEY=$tgt_key
CONTENTUNDERSTANDING_TARGET_RESOURCE_ID=$tgt_rid
CONTENTUNDERSTANDING_TARGET_REGION=$tgt_region
EOF
        fi

        echo "  ✓ Wrote $ENV_FILE"
    else
        cat > "$ENV_FILE" <<'EOF'
# Azure AI Content Understanding - Environment Variables
# Fill in your values below.

# Required: Your Microsoft Foundry resource endpoint
CONTENTUNDERSTANDING_ENDPOINT=https://<your-resource>.services.ai.azure.com/

# Optional: API key (leave empty to use DefaultAzureCredential via az login)
CONTENTUNDERSTANDING_KEY=

# Model deployment names (used by Sample00_UpdateDefaults)
GPT_4_1_DEPLOYMENT=gpt-4.1
GPT_4_1_MINI_DEPLOYMENT=gpt-4.1-mini
TEXT_EMBEDDING_3_LARGE_DEPLOYMENT=text-embedding-3-large
EOF
        echo "  ✓ Wrote template to $ENV_FILE — please edit it before running samples."
    fi
fi
echo ""

# Summary
echo "=== Setup Complete ==="
echo ""
echo "Next steps:"
echo ""
echo "  1. Load .env into your current shell (Java reads System.getenv, so this is REQUIRED):"
echo "       cd $PACKAGE_ROOT"
echo "       set -a && source .env && set +a"
echo ""
echo "  2. (One-time per Foundry resource) Configure model defaults:"
echo "       mvn exec:java \\"
echo "         -Dexec.mainClass=\"com.azure.ai.contentunderstanding.samples.Sample00_UpdateDefaults\" \\"
echo "         -Dexec.classpathScope=test -Djacoco.skip=true -q"
echo ""
echo "  3. Run a sample:"
echo "       mvn exec:java \\"
echo "         -Dexec.mainClass=\"com.azure.ai.contentunderstanding.samples.Sample02_AnalyzeUrl\" \\"
echo "         -Dexec.classpathScope=test -Djacoco.skip=true -q"
echo ""
echo "     Or use the sample-run helper:"
echo "       .github/skills/cu-sdk-sample-run/scripts/run_sample.sh Sample02_AnalyzeUrl --env .env"
echo ""
